UserObject.plantUmlData:
{
  "data": "@startuml
skinparam linetype ortho
skinparam nodesep 120
skinparam ranksep 130
skinparam classAttributeIconSize 0
skinparam packageStyle rectangle
skinparam roundcorner 10
skinparam DefaultFontName Arial

' ==========================================
' PRESENTATION LAYER (Top Row)
' ==========================================
package "Suppliers UI" #E8F8F5 {
    class SupplierDashboard <<GUI>> {
        - suppliersTable: TableView
    }
    class OrderDashboard <<GUI>> {
        - ordersTable: TableView
    }
    class SupplierController <<Controller>>
    class OrderController <<Controller>> {
        + processPeriodicOrders(today: Date)
    }
    SupplierDashboard "1" -down-> "1" SupplierController : triggers
    OrderDashboard "1" -down-> "1" OrderController : triggers
}

package "Employees UI" #E8F8F5 {
    class EmployeesDashboard <<GUI>> {
        - employeesTable: TableView
        - shiftsTable: TableView
    }
    class EmployeeController <<Controller>>
    class ManagerController <<Controller>>
    class BranchManagerController <<Controller>>
    EmployeesDashboard "1" -down-> "1" EmployeeController : triggers
    EmployeesDashboard "1" -down-> "1" ManagerController : triggers
    EmployeesDashboard "1" -down-> "1" BranchManagerController : triggers
}

package "Transportation UI" #E8F8F5 {
    class TransportationDashboard <<GUI>> {
        - deliveriesTable: TableView
        - trucksTable: TableView
    }
    class TransportationController <<Controller>> {
        + issueDelivery(...)
    }
    TransportationDashboard "1" -down-> "1" TransportationController : triggers
}

package "Inventory UI" #E8F8F5 {
    class InventoryDashboard <<GUI>> {
        - productsTable: TableView
        - defectsTable: TableView
    }
    class InventoryController <<Controller>>
    InventoryDashboard "1" -down-> "1" InventoryController : triggers
}

package "Core UI" #E8F8F5 {
    class LoginScreen <<GUI>> {
        + routeUser(role)
    }
    class AuthController <<Controller>> {
        + login(passcode)
    }
    LoginScreen "1" -down-> "1" AuthController : triggers
}

' ==========================================
' SERVICE LAYER (Middle Row)
' ==========================================
package "Suppliers Services" #F5EEF8 {
    class SupplierService <<Service>> {
        + getCheapestSupplier(barcode, amount)
    }
    class OrderService <<Service>> {
        + processPeriodicOrders(today: Date)
        + generateShortageOrder(barcode, amount)
    }
}

package "Employees Services" #F5EEF8 {
    class EmployeeService <<Service>> {
        + getEmployeeDetails(id: String): EmployeeDL
    }
    class ManagerService <<Service>> {
        + assignShift(empId, date)
    }
    class BranchManagerService <<Service>>
}

package "Transportation Services" #F5EEF8 {
    class TransportationService <<Service>> {
        + issueDelivery(truckId, driverId, date, dests)
        + validateDriverLicense(driverId, truckWeight)
    }
}

package "Inventory Services" #F5EEF8 {
    class InventoryService <<Service>> {
        - checkAndAlertShortages(barcode)
    }
}

package "Core Services" #F5EEF8 {
    class AuthService <<Service>> {
        + authenticate(user, pass)
    }
}

' ==========================================
' WIRING LAYER 1 TO LAYER 2 (Vertical Pull)
' ==========================================
SupplierController "1" -down-> "1" SupplierService
OrderController "1" -down-> "1" OrderService

EmployeeController "1" -down-> "1" EmployeeService
ManagerController "1" -down-> "1" ManagerService
BranchManagerController "1" -down-> "1" BranchManagerService

TransportationController "1" -down-> "1" TransportationService

InventoryController "1" -down-> "1" InventoryService

AuthController "1" -down-> "1" AuthService

' ==========================================
' DOMAIN & DATA LAYER (Bottom Row)
' ==========================================
package "Suppliers Domain" #FEF9E7 {
    class SupplierFacade <<Facade>>
    class OrderFacade <<Facade>>
    class SqlSupplierDAO <<DAO>>
    class SqlOrderDAO <<DAO>>

    class SupplierDL <<Entity>> {
        - businessNumber: String
        - name: String
        - address: String
    }
    class ContactPersonDL <<Entity>> {
        - name: String
        - phone: String
        - email: String
    }
    class PaymentDetails <<Entity>> {
        - paymentCondition: String
    }
    class BankAccount <<Entity>> {
        - iban: String
    }
    class DeliveryTermsDL <<Entity>> {
        - deliveryDays: List<DayOfWeek>
        - supplierTransports: boolean
    }
    class AgreementDL <<Entity>> {
        - agreementId: int
        - startDate: LocalDate
    }
    class ProductLineDL <<Entity>> {
        - supplierCatalogId: int
        - name: String
        - basePrice: double
    }
    class DiscountPolicyDL <<Entity>> {
        - productDiscounts: Map
    }
    class DiscountBracketDL <<Entity>> {
        - minQuantity: int
        - discountPercentage: double
    }
    class OrderDL <<Entity>> {
        - orderId: int
        - orderDate: LocalDate
        - supplierBusinessNumber: String
        - totalPrice: double
    }
    class OrderItemDL <<Entity>> {
        - catalogId: int
        - productName: String
        - quantity: int
        - finalPrice: double
    }

    SupplierService "1" -down-> "1" SupplierFacade
    SupplierFacade "1" -down-> "1" SqlSupplierDAO
    OrderService "1" -down-> "1" OrderFacade
    OrderFacade "1" -down-> "1" SqlOrderDAO

    SupplierFacade "1" -down-> "1..*" SupplierDL
    SupplierDL "1" *-down- "1..*" ContactPersonDL
    SupplierDL "1" *-down- "1" PaymentDetails
    SupplierDL "1" *-down- "1" BankAccount
    SupplierDL "1" *-down- "1" DeliveryTermsDL
    SupplierDL "1" *-down- "1..*" AgreementDL
    AgreementDL "1" *-down- "1..*" ProductLineDL
    AgreementDL "1" *-down- "1" DiscountPolicyDL
    DiscountPolicyDL "1" *-down- "1..*" DiscountBracketDL

    OrderFacade "1" -down-> "0..*" OrderDL
    OrderDL "1" *-down- "1..*" OrderItemDL
}

package "Employees Domain" #FEF9E7 {
    class EmployeesFacade <<Facade>>
    class SqlEmployeesDAO <<DAO>>
    class ShiftManagerDL <<Entity>> {

    }
    class StaffingRequirementDL <<Entity>> {
      - role: RoleDL
      - amount: int
    }
    class ShiftAssignmentDL <<Entity>> {
      - employee: EmployeeDL
      - role: RoleDL
    }
    class AvailabilitySubmissionDL <<Entity>> {
      - employee: EmployeeDL
      - shifts: Map<ShiftKey, Boolean>
    }

    class EmployeeDL <<Entity>> {
        - id: String
        - name: String
        - licenseType: String
        - jobScope: JobScope
    }
    class ShiftDL <<Entity>> {
        - date: Date
        - shiftType: ShiftType
    }
    class BranchDL <<Entity>> {
        - branchId: int
        - location: String
        - branchManagerId: String
        - startDate: WeekKey
    }
    class RoleDL <<Entity>> {
        - title: String
    }
    class RequestDL <<Entity>> {
        - requestType: String
        - status: String
    }

    ShiftManagerDL -up-|> "EmployeeDL"
    EmployeesService "1" -down-> "1" EmployeesFacade
    ManagerService "1" -down-> "1" EmployeesFacade
    BranchManagerService "1" -down-> "1" EmployeesFacade
    StaffingRequirementDL "1" -up-* "1..*" ShiftDL
    ShiftAssignmentDL "1" -up-* "1..*" ShiftDL

    EmployeesFacade "1" -down-> "1..*" AvailabilitySubmissionDL
    EmployeesFacade "1" -down-> "1" SqlEmployeesDAO
    EmployeesFacade "1" -down-> "1..*" EmployeeDL
    EmployeesFacade "1" -down-> "0..*" ShiftDL
    EmployeesFacade "1" -down-> "1..*" BranchDL
    EmployeesFacade "1" -down-> "1..*" RoleDL
    EmployeesFacade "1" -down-> "0..*" RequestDL
}

package "Transportation Domain" #FEF9E7 {
    class TransportationFacade <<Facade>>
    class SqlTransportationDAO <<DAO>>

    class TransportationManager <<Entity>> {
        - managerId: String
        - pendingDeliveries: List
    }
    class DeliveryDL <<Entity>> {
        - deliveryId: int
        - dispatchTime: Date
        - totalWeight: double
        - truckId: String
        - driverId: String
    }
    class TruckDL <<Entity>> {
        - licenseNumber: String
        - maxWeight: double
        - netWeight: double
    }
    class DriverDL <<Entity>> {
        - driverId: String
        - licenseType: String
        - name: String
    }
    class SiteDL <<Entity>> {
        - siteName: String
        - address: String
        - contactPerson: String
    }
    class DestinationDL <<Entity>> {
        - siteName: String
        - address: String
    }
    class CargoItemDL <<Entity>> {
        - barcode: String
        - weight: double
    }

    TransportationService "1" -down-> "1" TransportationFacade
    TransportationFacade "1" -down-> "1" SqlTransportationDAO

    TransportationFacade "1" -down-> "1" TransportationManager
    TransportationManager "1" -down-> "0..*" DeliveryDL
    TransportationFacade "1" -down-> "1..*" TruckDL
    TransportationFacade "1" -down-> "1..*" DriverDL
    TransportationFacade "1" -down-> "1..*" SiteDL

    DeliveryDL "1" *-down- "1..*" DestinationDL
    DestinationDL "1" *-down- "1..*" CargoItemDL

    DeliveryDL "1" -down-> "1" TruckDL
    DeliveryDL "1" -down-> "1" DriverDL
}

package "Inventory Domain" #FEF9E7 {
    class InventoryFacade <<Facade>>
    class SqlInventoryDAO <<DAO>>

    class ProductDL <<Entity>> {
        - barcode: String
        - name: String
        - minStock: int
        - shelfQuantity: int
        - warehouseQuantity: int
    }
    class ShelfLocation <<ValueObject>> {
        - aisle: String
        - position: int
    }
    class Warehouse <<ValueObject>> {
        - name: String
    }
    class DefectiveItemDL <<Entity>> {
        - defectId: int
        - barcode: String
        - amount: int
    }
    class CategoryDL <<Entity>> {
        - categoryId: int
        - name: String
    }
    class PromotionDL <<Entity>> {
        - discountPercentage: double
        - validUntil: Date
    }
    class LowStockAlert <<Entity>> {
        - alertId: int
        - barcode: String
    }
    class InventoryReport <<Entity>> {
        - reportId: int
        - creationDate: Date
    }

    InventoryService "1" -down-> "1" InventoryFacade
    InventoryFacade "1" -down-> "1" SqlInventoryDAO
    InventoryFacade "1" -down-> "1..*" ProductDL
    InventoryFacade "1" -down-> "0..*" DefectiveItemDL
    InventoryFacade "1" -down-> "1..*" CategoryDL
    InventoryFacade "1" -down-> "0..*" PromotionDL
    InventoryFacade "1" -down-> "0..*" LowStockAlert
    InventoryFacade "1" -down-> "0..*" InventoryReport

    ProductDL "1" *-down- "1" ShelfLocation
    ProductDL "1" *-down- "1" Warehouse
}

package "Core Domain" #FEF9E7 {
    class AuthFacade <<Facade>>
    class SessionManager
    class SqlAuthDAO <<DAO>>

    AuthService "1" -down-> "1" AuthFacade
    AuthFacade "1" -down-> "1" SessionManager
    AuthFacade "1" -down-> "1" SqlAuthDAO
}

' ==========================================
' ASSIGNMENT 2 INTEGRATIONS (Service -> Service)
' ==========================================

note bottom of InventoryService
  Integration 1: Shortage Order
  Inventory alerts Orders
end note
InventoryService ..> OrderService : <<invokes>>\ngenerateShortageOrder()

note bottom of TransportationService
  Integration 2: Route Planner
  Transportation validates Driver License
end note
TransportationService ..> EmployeeService : <<invokes>>\ngetEmployeeDetails()

@enduml",
  "format": "svg"
}
